# Starter guidance: Load task objects from CSV. Follow the prompt and edit the requested code below.
class BaseTask:
    VALID_PRIORITIES = {"low", "medium", "high"}

    def __init__(self, title, priority="medium", completed=False):
        if not title.strip():
            raise ValueError("title is required")
        if priority not in self.VALID_PRIORITIES:
            raise ValueError("priority must be low, medium, or high")
        self.title = title
        self.priority = priority
        self.completed = bool(completed)

    def mark_done(self):
        self.completed = True
        return self.completed

    def is_open(self):
        return not self.completed

    def summary(self):
        raise NotImplementedError("Subclasses must implement summary()")

